// Plane art for the autopilot takeoff. Three side/3-4-view craft — airliner,
// biplane (prop), and rocket — traced (potrace) from reference-style icons into
// currentColor vector paths at the character line-art weight. Each seats the
// session's pilot mascot in a clean cockpit knocked out of the plane. A plane is
// assigned per session deterministically, so different sessions fly different
// craft. Generated by iconwork/gen-plane-art.js — edit there, not here.
import { pilotArtGroup } from './character-art'

interface PlaneDef {
  /** SVG viewBox (includes headroom above the plane for the mascot). */
  vb: string
  /** Cockpit knockout (filled with --bg) so no plane lines cross the mascot. */
  ko: { cx: number; cy: number; rx: number; ry: number }
  /** Seated mascot: center, size (from the 512 pilot space), and tilt to match the craft. */
  pilot: { cx: number; cy: number; size: number; rot: number }
  /** Whole-craft level-out rotation (deg CW) applied about (cpx, cpy). */
  crot: number
  cpx: number
  cpy: number
  /** potrace transform for the traced path. */
  transform: string
  /** Traced plane outline (filled, currentColor). */
  d: string
}

