export type PlaneId = keyof typeof PLANES
export const PLANE_IDS = Object.keys(PLANES) as PlaneId[]

/** Deterministically assign a plane to a session id (stable across renders). */
export function planeFor(seed: string): PlaneId {
  let h = 0
  for (let i = 0; i < seed.length; i++) h = (h * 31 + seed.charCodeAt(i)) >>> 0
  return PLANE_IDS[h % PLANE_IDS.length]
}

interface PlaneCraftProps {
  planeId: PlaneId
  /** Character id whose pilot (aviator) art is seated in the craft. */
  characterId: string
}

/** One SVG: the plane in currentColor with the pilot mascot seated in a clean cockpit. */
export function PlaneCraft({ planeId, characterId }: PlaneCraftProps): JSX.Element {
  const def = PLANES[planeId] ?? PLANES.airliner
  const p = def.pilot
  return (
    <svg
      className="takeoff__plane"
      viewBox={def.vb}
      fill="currentColor"
      stroke="none"
      aria-hidden="true"
      focusable="false"
    >
      <g transform={`rotate(${def.crot} ${def.cpx} ${def.cpy})`}>
        <g transform={def.transform}>
          <path d={def.d} />
        </g>
        <ellipse cx={def.ko.cx} cy={def.ko.cy} rx={def.ko.rx} ry={def.ko.ry} fill="var(--bg)" />
        <g
          transform={`translate(${p.cx},${p.cy}) rotate(${p.rot}) scale(${p.size / 512}) translate(-256,-256)`}
          fill="currentColor"
          stroke="none"
        >
          {pilotArtGroup(characterId)}
        </g>
      </g>
    </svg>
  )
}
